#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define DISK_SIZE 1000
#define MAX_FILES 50
#define MAX_FILENAME 20

typedef struct {
    char filename[MAX_FILENAME];
    int start_block;
    int length;
    int allocated;
} FileControlBlock;

FileControlBlock file_table[MAX_FILES];
int free_space[DISK_SIZE]; // 0 = free, 1 = allocated

// Initialize file table and free space
void initialize() {
    memset(free_space, 0, sizeof(free_space));
    for (int i = 0; i < MAX_FILES; i++) {
        file_table[i].allocated = 0;
    }
}

// Allocate contiguous blocks to a file
int allocate_file(char* filename, int num_blocks) {
    int start = -1;
    int count = 0;

    // Find contiguous free blocks
    for (int i = 0; i < DISK_SIZE; i++) {
        if (free_space[i] == 0) {
            if (count == 0) start = i;
            count++;
            if (count >= num_blocks) break;
        } else {
            count = 0;
            start = -1;
        }
    }

    // Allocate if found contiguous space
    if (count >= num_blocks) {
        for (int i = start; i < start + num_blocks; i++) {
            free_space[i] = 1;
        }

        // Add to file table
        for (int i = 0; i < MAX_FILES; i++) {
            if (!file_table[i].allocated) {
                strcpy(file_table[i].filename, filename);
                file_table[i].start_block = start;
                file_table[i].length = num_blocks;
                file_table[i].allocated = 1;
                return start;
            }
        }
    }
    return -1; // No contiguous space found
}

// Display disk allocation status
void display_disk() {
    printf("\nDisk Allocation Status:\n");
    for (int i = 0; i < DISK_SIZE; i++) {
        printf("%d ", free_space[i]);
        if ((i + 1) % 50 == 0) printf("\n");
    }
    printf("\n\nFiles allocated:\n");
    for (int i = 0; i < MAX_FILES; i++) {
        if (file_table[i].allocated) {
            printf("%s: blocks %d-%d (%d blocks)\n",
                   file_table[i].filename,
                   file_table[i].start_block,
                   file_table[i].start_block + file_table[i].length - 1,
                   file_table[i].length);
        }
    }
}

int main() {
    initialize();

    allocate_file("file1.txt", 10);
    allocate_file("file2.txt", 15);
    allocate_file("file3.txt", 5);

    display_disk();
    return 0;
}

class BitVectorFreeSpace:
    """Free space management using Bit Vector (Bitmap)"""

    def __init__(self, num_blocks):
        self.num_blocks = num_blocks
        # 0 = free, 1 = allocated
        self.bitmap = [0] * num_blocks

    def allocate_block(self):
        """Find first free block and allocate it"""
        for i in range(self.num_blocks):
            if self.bitmap[i] == 0:
                self.bitmap[i] = 1
                return i
        return -1  # No free block available

    def allocate_contiguous(self, num_blocks):
        """Find contiguous free blocks"""
        start = -1
        count = 0

        for i in range(self.num_blocks):
            if self.bitmap[i] == 0:
                if count == 0:
                    start = i
                count += 1
                if count >= num_blocks:
                    # Allocate found blocks
                    for j in range(start, start + num_blocks):
                        self.bitmap[j] = 1
                    return start
            else:
                count = 0
                start = -1

        return -1

    def free_block(self, block_num):
        """Free a specific block"""
        if 0 <= block_num < self.num_blocks:
            self.bitmap[block_num] = 0
            return True
        return False

    def free_contiguous(self, start, num_blocks):
        """Free contiguous blocks starting from start"""
        for i in range(start, start + num_blocks):
            if 0 <= i < self.num_blocks:
                self.bitmap[i] = 0

    def get_free_count(self):
        """Count total free blocks"""
        return self.bitmap.count(0)

    def display_bitmap(self):
        """Display bitmap in readable format"""
        print(f"Total blocks: {self.num_blocks}")
        print(f"Free blocks: {self.get_free_count()}")
        print("Bitmap: ", end="")
        for i, bit in enumerate(self.bitmap):
            print(bit, end=" ")
            if (i + 1) % 20 == 0:
                print()
        print("\n")

# Example usage
fs = BitVectorFreeSpace(100)

# Allocate some blocks
block1 = fs.allocate_block()
block2 = fs.allocate_block()

# Allocate 5 contiguous blocks
start = fs.allocate_contiguous(5)
print(f"Allocated contiguous blocks starting at: {start}")

# Display current state
fs.display_bitmap()

# Free blocks
fs.free_block(block1)
fs.free_contiguous(start, 5)

print("After freeing:")
fs.display_bitmap()
